import{_ as e,p as t,q as o,a1 as c}from"./framework-96b046e1.js";const a="/images/ESP32_DEVKIT_V1.png",s="/images/ESP32-01.png",i="/images/ESP32-02.png",p="/images/ESP32-03.png",r={},d=c('<h2 id="devkit-v1" tabindex="-1"><a class="header-anchor" href="#devkit-v1" aria-hidden="true">#</a> DEVKIT_V1</h2><p>下面是我的第一款 <code>ESP32</code> 开发板。</p><p><img src="'+a+'" alt="ESP32_DEVKIT_V1.png"></p><p>该板子用到模组是 <code>ESP32­WROOM­32</code> ，已经是老模组了，官方不在推荐使用。</p><p><code>ESP32-WROOM-32</code> 是一款通用型 <code>Wi-Fi + Bluetooth + Bluetooth LE MCU</code> 模组，功能强大，用途广泛，可以用 于低功耗传感器网络和要求极高的任务，例如语音编码、音频流和 <code>MP3</code> 解码等。</p><div class="custom-container tip"><p class="custom-container-title">TIP</p><p>此款模组的核心是 ESP32-D0WDQ6 芯片 *，具有可扩展、自适应的特点。两个 CPU 核可以被单独控制。时钟 频率的调节范围为 80 MHz 到 240 MHz。用户可以切断 CPU 的电源，利用低功耗协处理器来不断地监测外设 的状态变化或某些模拟量是否超出阈值。ESP32 还集成了丰富的外设，包括电容式触摸传感器、霍尔传感器、 低噪声传感放大器，SD 卡接口、以太网接口、高速 SDIO/SPI、UART、I2S 和 I2C 等。</p><p>ESP32 的操作系统是带有 LwIP 的 freeRTOS，还内置了带有硬件加速功能的 TLS 1.2。芯片同时支持 OTA 加密 升级，方便用户在产品发布之后继续升级。</p><p><img src="'+s+'" alt=""><img src="'+i+'" alt=""></p></div><h3 id="模组引脚定义" tabindex="-1"><a class="header-anchor" href="#模组引脚定义" aria-hidden="true">#</a> 模组引脚定义</h3><p><img src="'+p+'" alt=""></p>',8),n=[d];function _(l,m){return t(),o("div",null,n)}const S=e(r,[["render",_],["__file","esp32-board.html.vue"]]);export{S as default};
